# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

class Account:
    def __init__(self, name, balance=0):
        self.name = name
        self.balance = balance

    def deposit(self, amount):
        if amount > 0:
            self.balance += amount
            return True
        else:
            print("Invalid deposit amount")
            return False

    def withdraw(self, amount):
        if amount <= self.balance:
            self.balance -= amount
            return True
        else:
            print("Insufficient balance to complete withdrawal.")
            return False

    def check_balance(self):
        return self.balance

def process_transaction(account, transaction_type, *args):
    if transaction_type == "deposit":
        account.deposit(*args[0])
    elif transaction_type == "withdraw":
        account.withdraw(*args[0])
    else:
        print("Invalid transaction type.")

# Example usage:
account1 = Account("John Doe", 1000)
process_transaction(account1, "deposit", 500)
print(account1.check_balance()) # Output: 1500
process_transaction(account1, "withdraw", 300)
print(account1.check_balance()) # Output: 1200